import{_ as t,o,c as r,ad as a}from"./chunks/framework.DdcUsuRQ.js";const p=JSON.parse('{"title":"Hue lock","description":"Pin a role to an exact OKLCH hue regardless of the seed. The opposite knob to derivedFrom + hueOffset.","frontmatter":{"title":"Hue lock","description":"Pin a role to an exact OKLCH hue regardless of the seed. The opposite knob to derivedFrom + hueOffset.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/role-schema/hue-lock"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/role-schema/hue-lock"}],["meta",{"property":"og:title","content":"Hue lock: iridis"}],["meta",{"property":"og:description","content":"Pin a role to an exact OKLCH hue regardless of the seed. The opposite knob to derivedFrom + hueOffset."}],["meta",{"name":"twitter:title","content":"Hue lock: iridis"}],["meta",{"name":"twitter:description","content":"Pin a role to an exact OKLCH hue regardless of the seed. The opposite knob to derivedFrom + hueOffset."}],["meta",{"name":"description","content":"Pin a role to an exact OKLCH hue regardless of the seed. The opposite knob to derivedFrom + hueOffset."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Role Schema\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":4,\\"name\\":\\"Hue lock\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema/hue-lock\\"}]}"]]},"headers":[],"relativePath":"reference/role-schema/hue-lock.md","filePath":"reference/role-schema/hue-lock.md","lastUpdated":1779033869000}'),d={name:"reference/role-schema/hue-lock.md"};function i(c,e,s,h,n,l){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="hue-lock" tabindex="-1">Hue lock <a class="header-anchor" href="#hue-lock" aria-label="Permalink to &quot;Hue lock&quot;">​</a></h1><p>A role with <code>hueLock</code> declared takes a fixed OKLCH hue, ignoring whatever hue the seed produces. Use it when a role&#39;s identity depends on a specific colour family (<code>success</code> is <strong>green</strong>, <code>error</code> is <strong>red</strong>, <code>link</code> is <strong>blue</strong>), regardless of what the user picked as a brand seed.</p><h2 id="shape" tabindex="-1">Shape <a class="header-anchor" href="#shape" aria-label="Permalink to &quot;Shape&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td><code>hueLock</code></td><td><code>number</code></td><td>Degrees on the OKLCH hue ring (<code>0..360</code>). Optional. Mutually exclusive with <code>derivedFrom</code>.</td></tr></tbody></table><p>When <code>hueLock</code> is present, the engine ignores the seed&#39;s hue for this role and uses <code>hueLock</code> directly. Lightness and chroma still come from the seed (clamped into the role&#39;s envelopes).</p><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>resolve:roles</code> substitutes the locked hue value before checking the seed against the role&#39;s lightness / chroma envelopes:</p><ol><li>Take the seed&#39;s <code>L</code> and <code>C</code>.</li><li>Replace its <code>h</code> with <code>hueLock</code>.</li><li>Clamp <code>L</code> and <code>C</code> into <code>lightnessRange</code> / <code>chromaRange</code>.</li><li>Emit the role.</li></ol><h2 id="what-it-means" tabindex="-1">What it means <a class="header-anchor" href="#what-it-means" aria-label="Permalink to &quot;What it means&quot;">​</a></h2><p>Hue lock is the <strong>anti-parametric</strong> option. <code>derivedFrom</code> says &quot;follow another role&quot;; <code>hueLock</code> says &quot;follow nobody, I have my own hue.&quot; Together they&#39;re the two ways a role can refuse to drift with the seed.</p><p>Typical hue-lock anchors:</p><table tabindex="0"><thead><tr><th>Role</th><th>Typical hue</th></tr></thead><tbody><tr><td><code>success</code></td><td><code>135</code> (green)</td></tr><tr><td><code>warning</code></td><td><code>75</code> (yellow)</td></tr><tr><td><code>error</code> / <code>critical</code></td><td><code>25</code> (red)</td></tr><tr><td><code>info</code></td><td><code>220</code> (blue)</td></tr><tr><td><code>link</code></td><td><code>255</code> (indigo)</td></tr></tbody></table><h2 id="how-to-author" tabindex="-1">How to author <a class="header-anchor" href="#how-to-author" aria-label="Permalink to &quot;How to author&quot;">​</a></h2><ul><li>Use <code>hueLock</code> on roles whose <strong>semantic meaning</strong> depends on cultural colour associations (success = green, error = red).</li><li>Don&#39;t lock a brand role&#39;s hue; the brand IS what the user is supplying as the seed.</li><li>Pair <code>hueLock</code> with a chroma range tight enough that the locked hue reads clearly. A locked green at <code>C ≤ 0.04</code> is just a slightly-warm grey.</li><li><code>hueLock</code> and <code>derivedFrom</code> together is a contradiction; the schema validator rejects roles that declare both.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./derived-from">Derived roles</a>: the opposite knob, inherit a parent&#39;s hue with an offset.</li><li><a href="./chroma-range">Chroma range</a>: controls how much the locked hue can be expressed.</li><li><a href="./../../concepts/role-schemas">Role schemas overview</a>.</li></ul>',16)])])}const m=t(d,[["render",i]]);export{p as __pageData,m as default};
